import { Component, OnInit } from '@angular/core';
import { Student, StudentService } from '../../../core/services/student.service';
import { BulletinService, BulletinData } from '../../../core/services/bulletin.service';
import { NotificationService } from '../../../core/services/notification.service';

@Component({
  selector: 'app-bulletin',
  templateUrl: './bulletin.component.html',
  styleUrls: ['./bulletin.component.css']
})
export class BulletinComponent implements OnInit {
  students: Student[] = [];
  selectedStudent: Student | null = null;
  bulletinData: BulletinData | null = null;
  selectedTerm = '';
  terms = ['Trimestre 1', 'Trimestre 2', 'Trimestre 3'];
  loading = false;
  allBulletins: BulletinData[] = [];
  showAllBulletins = false;
  currentDate = new Date(); // <-- PROPRIÉTÉ AJOUTÉE

  constructor(
    private studentService: StudentService,
    private bulletinService: BulletinService,
    private notification: NotificationService
  ) {}

  ngOnInit() {
    this.studentService.getAll().subscribe(s => this.students = s);
  }

  loadBulletin() {
    if (!this.selectedStudent) {
      this.notification.warning('Sélectionnez un étudiant');
      return;
    }

    this.loading = true;
    this.bulletinService.getBulletinData(this.selectedStudent.id!, this.selectedTerm).subscribe({
      next: (data) => {
        this.bulletinData = data;
        this.loading = false;
      },
      error: () => {
        this.notification.error('Erreur lors du chargement du bulletin');
        this.loading = false;
      }
    });
  }

  generateAllBulletins() {
    this.notification.info('Génération de tous les bulletins en cours...');
    this.showAllBulletins = true;
    this.allBulletins = [];

    let completed = 0;
    this.students.forEach(student => {
      this.bulletinService.getBulletinData(student.id!, this.selectedTerm).subscribe({
        next: (data) => {
          this.allBulletins.push(data);
          completed++;
          if (completed === this.students.length) {
            this.notification.success(`${this.allBulletins.length} bulletins générés avec succès`);
          }
        },
        error: () => {
          completed++;
        }
      });
    });
  }

  printBulletin() {
    window.print();
  }

  downloadBulletin() {
    this.notification.info('Téléchargement du bulletin...');
    setTimeout(() => {
      this.notification.success('Bulletin téléchargé');
    }, 1000);
  }

  downloadAllBulletins() {
    this.notification.info('Téléchargement de tous les bulletins...');
    setTimeout(() => {
      this.notification.success(`${this.allBulletins.length} bulletins téléchargés`);
    }, 2000);
  }

  getGradeLevel(score: number): string {
    if (score >= 16) return 'Excellent';
    if (score >= 14) return 'Bien';
    if (score >= 12) return 'Assez bien';
    if (score >= 10) return 'Passable';
    return 'Insuffisant';
  }

  getGradeClass(score: number): string {
    if (score >= 16) return 'grade-excellent';
    if (score >= 14) return 'grade-bien';
    if (score >= 12) return 'grade-assez-bien';
    if (score >= 10) return 'grade-passable';
    return 'grade-insuffisant';
  }
}
